#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int compare(const void *a, const void *b) {
    return (*(long *)a - *(long *)b);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        long s[n];
        for (int i = 0; i < n; i++) {
            scanf("%ld", &s[i]);
        }
        qsort(s, n, sizeof(long), compare);

        long long minval = LLONG_MAX;
        for (int i = 1; i < n; i++) {
            long long diff = s[i] - s[i - 1];
            if (diff < minval) {
                minval = diff;
            }
        }

        printf("%lld\n", minval);
    }
    return 0;
}

