function Horses(input) {
    const lines = input.trim().split('\n');
    const T = parseInt(lines[0]);

    let index = 1;
    for (let t = 0; t < T; t++) {
        const N = parseInt(lines[index++]);
        const skills = lines[index++].split(' ').map(Number);

        skills.sort((a, b) => a - b); // Sort skills in ascending order

        let minDifference = Infinity;
        for (let i = 1; i < N; i++) {
            const difference = skills[i] - skills[i - 1];
            minDifference = Math.min(minDifference, difference);
        }

        console.log(minDifference);
    }
}

